/**
 * Custom Jest resolver that supports package.json "exports" maps.
 * Required for Angular 21+ which uses exports instead of physical subdirectories.
 */
module.exports = (path, options) => {
  try {
    return options.defaultResolver(path, {
      ...options,
      conditions: options.conditions || ['require', 'node', 'default'],
      packageFilter(pkg) {
        // If the package has exports, let Node's resolution handle it
        if (pkg.exports) {
          return pkg;
        }
        return {
          ...pkg,
          main: pkg.main || pkg.es2015 || pkg.module,
        };
      },
    });
  } catch (error) {
    // Fallback: try Node's native require.resolve
    try {
      return require.resolve(path, {
        paths: [options.basedir],
      });
    } catch {
      throw error;
    }
  }
};

